loadstring(game:HttpGet("https://raw.githubusercontent.com/xHeptc/Kavo-UI-Library/main/source.lua"))();local Window = Library.CreateLib("Rivals • Enhancements", "DarkTheme");local player=game.Players.LocalPlayer;local mouse=player:GetMouse();local runService=game:GetService("RunService");local userInputService=game:GetService("UserInputService");local camera=workspace.CurrentCamera;local lplr=player;local settings={silentAim=false,aimbot=false,magnetAim=false,fovCircle=false,visibleCheck=true,smoothing=0.5,aimPart="Head",fly=false,noclip=false,speed=false,esp=false,flySpeed=50,walkSpeed=16,jumpPower=50,teamCheck=true,magnetStrength=50,magnetAngle=10,magnetDistance=50,fovRadius=200,hitChance=100,triggerDelay=25,smoothingValue=50,bulletTracerLife=1.0,espTextSize=11,skeletonThickness=2,};local function getAimedTarget(mousePos)local bestTarget=nil;local closestDist=math.huge;for _,targetPlayer in pairs(game.Players:GetPlayers())do if targetPlayer~=player and targetPlayer.Character and targetPlayer.Character:FindFirstChild("Head")then if settings.teamCheck and targetPlayer.Team==player.Team then continue end;local humanoid=targetPlayer.Character:FindFirstChildOfClass("Humanoid");if humanoid and humanoid.Health>0 then local screenPos,onScreen=workspace.CurrentCamera:WorldToViewportPoint(targetPlayer.Character.Head.Position);if onScreen then local dist=(Vector2.new(mousePos.X,mousePos.Y)-Vector2.new(screenPos.X,screenPos.Y)).Magnitude;if dist<settings.magnetDistance and dist<closestDist then closestDist=dist;bestTarget=targetPlayer.Character.Head end end end end end;return bestTarget,closestDist end;local CombatTab=Window:NewTab("⚔️ Combat");local AimbotSection=CombatTab:NewSection("Aimbot / Silent Aim");AimbotSection:NewToggle("Silent Aim","Manipulates hit registration",function(state)settings.silentAim=state end);AimbotSection:NewToggle("Aimbot","Smooth aim assist",function(state)settings.aimbot=state end);AimbotSection:NewToggle("Magnet Aim","Mouse magnetically pulls to