antly",function(state)settings.instantReload=state end);local VisualsTab=Window:NewTab("👁️ Visuals");local ESPsection=VisualsTab:NewSection("ESP Settings");ESPsection:NewToggle("Enable ESP","See players through walls",function(state)settings.esp=state;if state then spawn(function()while settings.esp do for _,v in pairs(game.Players:GetPlayers())do if v~=player and v.Character and v.Character:FindFirstChild("HumanoidRootPart")then if not v.Character:FindFirstChild("ESP_Box")then local box=Instance.new("BoxHandleAdornment");box.Name="ESP_Box";box.Size=v.Character.HumanoidRootPart.Size*2.5;box.Adornee=v.Character.HumanoidRootPart;box.Color3=v.TeamColor==player.TeamColor and Color3.new(0,1,0)or Color3.new(1,0,0);box.Transparency=0.7;box.ZIndex=10;box.AlwaysOnTop=true;box.Parent=v.Character.HumanoidRootPart end end end;wait(0.5)end end)else for _,v in pairs(game.Players:GetPlayers())do if v.Character and v.Character:FindFirstChild("HumanoidRootPart")then local box=v.Character.HumanoidRootPart:FindFirstChild("ESP_Box");if box then box:Destroy()end end end end end);ESPsection:NewLabel("Text Size px (8-20):");local textSizeInput=Instance.new("TextBox");textSizeInput.Size=UDim2.new(0,150,0,25);textSizeInput.BackgroundColor3=Color3.fromRGB(25,25,35);textSizeInput.TextColor3=Color3.fromRGB(200,200,255);textSizeInput.BorderColor3=Color3.fromRGB(60,100,200);textSizeInput.Text=tostring(settings.espTextSize);ESPsection:AddElement(textSizeInput);textSizeInput.FocusLost:Connect(function()local val=tonumber(textSizeInput.Text);if val and val>=8 and val<=20 then settings.espTextSize=val else textSizeInput.Text=tostring(settings.espTextSize)end end);ESPsection:NewLabel("Skeleton Thickness (1-5):");local thickInput=Instance.new("TextBox");thickInput.Size=UDim2.new(0,150,0,25);thickInput.BackgroundColor3=Color3.fromRGB(25,25,35);thickInput.TextColor3=Color3.fromRGB(200,200,255);thickInput.BorderColor3=Color3.fromRGB(60,100,200);thickInput.Text=tostring(settings.skeletonThickness);ESPsection:AddElement(thickInput);thickInput.FocusLost:Connect(function()local val=tonumber(thickInput.Text);if val and val>=1 and val<=5 then settings.skeletonThickness=val else thickInput.Text=tostring(settings.skeletonThickness)end end);local MovementTab=Window:NewTab("🏃 Movement");local MoveSection=MovementTab:NewSection("Movement Values");MoveSection:NewToggle("Fly","Enable flight",function(state)settings.fly=state end);MoveSection:NewLabel("Fly Speed (10-200):");local flyInput=Instance.new("TextBox");flyInput.Size=UDim2.new(0,150,0,25);flyInput.BackgroundColor3=Color3.fromRGB(25,25,35);flyInput.TextColor3=Color3.fromRGB(200,200,255);flyInput.BorderColor3=Color3.fromRGB(60,100,200);flyInput.Text=tostring(settings.flySpeed);MoveSection:AddElement(flyInput);flyInput.FocusLost:Connect(function()local val=tonumber(flyInput.Text);if val and val>=10 and val<=200 then settings.flySpeed=val else flyInput.Text=tostring(settings.flySpeed)end end);MoveSection:NewToggle("Speed","Increase walk speed",function(state)settings.speed=state end);MoveSection:NewLabel("Walk Speed (16-100):");local walkInput=Instance.new("TextBox");walkInput.Size=UDim2.new(0,150,0,25);walkInput.BackgroundColor3=Color3.fromRGB(25,25,35);walkInput.TextColor3=Color3.fromRGB(200,200,255);walkInput.BorderColor3=Color3.fromRGB(60,100,200);walkInput.Text=tostring(settings.walkSpeed);MoveSection:AddElement(walkInput);walkInput.FocusLost:Connect(function()local val=tonumber(walkInput.Text);if val and val>=16 and val<=100 then settings.walkSpeed=val else walkInput.Text=tostring(settings.walkSpeed)end end);MoveSection:NewToggle("Noclip","Walk through walls",function(state)settings.noclip=state end);local SettingsTab=Window:NewTab("⚙️ Settings");local ConfigSection=SettingsTab:NewSection("Configuration");ConfigSection:NewKeybind("Toggle UI","Opens/closes menu",Enum.KeyCode.RightShift,function()Library:ToggleUI()end);ConfigSection:NewToggle("Team Check","Don't aim at teammates",function(state)settings.teamCheck=state end);runService.RenderStepped:Connect(function()if settings.magnetAim then local mousePos=userInputService:GetMouseLocation();local target,dist=getAimedTarget(Vector2.new(mousePos.X,mousePos.Y));if target then local screenPos=camera:WorldToViewportPoint(target.Position);local currentPos=Vector2.new(mousePos.X,mousePos.Y);local targetScreenPos=Vector2.new(screenPos.X,screenPos.Y);local moveVector=(targetScreenPos-currentPos)*(settings.magnetStrength/100);if moveVector.Magnitude<50 then local newPos=currentPos+moveVector;mouse:Move(newPos.X,newPos.Y)end end end;if settings.aimbot or settings.silentAim then local closestTarget=nil;local closestDistance=math.huge;for _,v in pairs(game.Players:GetPlayers())do if v~=player and v.Character and v.Character:FindFirstChild(settings.aimPart)and v.Character:FindFirstChildOfClass("Humanoid")and v.Character.Humanoid.Health>0 then if settings.teamCheck and v.Team==player.Team then continue end;local targetPos=v.Character[settings.aimPart].Position;local screenPos,onScreen=camera:WorldToScreenPoint(targetPos);if onScreen then local distance=(Vector2.new(screenPos.X,screenPos.Y)-Vector2.new(camera.ViewportSize.X/2,camera.ViewportSize.Y/2)).Magnitude;if distance<closestDistance and distance<settings.fovRadius then closestDistance=distance;closestTarget=v end end end end;if closestTarget and closestTarget.Character and closestTarget.Character:FindFirstChild(settings.aimPart)then local targetPos=closestTarget.Character[settings.aimPart].Position;if settings.aimbot then local currentLook=camera.CFrame.LookVector;local targetLook=(targetPos-camera.CFrame.Position).Unit;local newLook=currentLook:Lerp(targetLook,settings.smoothing);camera.CFrame=CFrame.new(camera.CFrame.Position,camera.CFrame.Position+newLook)end;if settings.silentAim then if math.random(1,100)<=settings.hitChance then mouse.Target=closestTarget.Character[settings.aimPart];mouse.Hit=CFrame.new(targetPos)end end end end end);spawn(function()while true do wait();if settings.fly and player.Character then local root=player.Character:FindFirstChild("HumanoidRootPart");local humanoid=player.Character:FindFirstChildOfClass("Humanoid");if root and humanoid then humanoid.PlatformStand=true;local moveDir=Vector3.new();if userInputService:IsKeyDown(Enum.KeyCode.W)then moveDir=moveDir+camera.CFrame.LookVector end;if userInputService:IsKeyDown(Enum.KeyCode.S)then moveDir=moveDir-camera.CFrame.LookVector end;if userInputService:IsKeyDown(Enum.KeyCode.A)then moveDir=moveDir-camera.CFrame.RightVector end;if userInputService:IsKeyDown(Enum.KeyCode.D)then moveDir=moveDir+camera.CFrame.RightVector end;if userInputService:IsKeyDown(Enum.KeyCode.Space)then moveDir=moveDir+Vector3.new(0,1,0)end;if userInputService:IsKeyDown(Enum.KeyCode.LeftControl)then moveDir=moveDir-Vector3.new(0,1,0)end;root.Velocity=moveDir*settings.flySpeed end end end end);spawn(function()while true do wait();if settings.speed and player.Character and player.Character:FindFirstChildOfClass("Humanoid")then player.Character:FindFirstChildOfClass("Humanoid").WalkSpeed=settings.walkSpeed end end end);spawn(function()while true do wait();if settings.noclip and player.Character then for _,v in pairs(player.Character:GetChildren())do if v:IsA("BasePart")then v.CanCollide=false end end end end end);mouse.Button1Down:Connect(function()if settings.triggerbot and mouse.Target and mouse.Target.Parent and mouse.Target.Parent:FindFirstChildOfClass("Humanoid")then wait(settings.triggerDelay/1000);mouse1click()end end);userInputService.InputBegan:Connect(function(input,gameProcessed)if gameProcessed then return end;if input.KeyCode==Enum.KeyCode.R and settings.instantReload then local character=player.Character;if character and character:FindFirstChildWhichIsA("Tool")then local tool=character:FindFirstChildWhichIsA("Tool");if tool and tool:FindFirstChild("Reload")then tool.Reload.Value=tool.Reload.MaxValue end end end end);Library:Notify("✅ Rivals script loaded! Press RightShift");Library:Notify("